 local function StartWearingOff(self, wearofftime, ...) local owner = self.inst local ft = wearofftime or self.wearofftime or 0x5 local qu = owner and owner.GetCharacterBonus and owner:GetCharacterBonus( "quickunfreeze" ) or 0x0 qu = math.max(0x0, math.min(qu, 0x1)) if qu > 0x0 then wearofftime = math.max(0.001, ft * (0x1 - qu)) end return self.dycOldStartWearingOff(self, wearofftime, ...) end local function Freeze(self, freezetime, ...) local owner = self.inst local immunity = owner and owner.GetCharacterBonus and owner:GetCharacterBonus( "sacreddefense" ) > 0x0 if immunity then self.coldness = 0x0 return end return self.dycOldFreeze(self, freezetime, ...) end local function Unfreeze(self, ...) local inst = self.inst inst:DoTaskInTime(FRAMES, function() if inst:IsValid() and not self:IsFrozen() and inst.sg and inst.sg.sg and inst.sg.currentstate.name == "frozen" then if inst.sg.sg.states.hit then inst.sg:GoToState( "hit" ) else inst.sg:GoToState( "idle" ) end end end) local retVal = self.dycOldUnfreeze(self, ...) return retVal end local function DYCFreezable(self) self.dycOldStartWearingOff = self.StartWearingOff self.StartWearingOff = StartWearingOff self.dycOldFreeze = self.Freeze self.Freeze = Freeze self.dycOldUnfreeze = self.Unfreeze self.Unfreeze = Unfreeze end return DYCFreezable 